import React from 'react';

export default function AboutPage() {
  return (
    <div className="page page-about">
      <h1>About Smart Travel</h1>
      <p className="lead">Prototype front-end for planning trips with AI-driven suggestions and filters.</p>
      <p>This prototype demonstrates free-text search parsing, recommendations, guest access and saved trips (local only).</p>
    </div>
  );
}
